=Extract financial data from this email:

Subject: {{ $json.subject }}
From: {{ $json.from.value[0].address }}
Date: {{ $json.date }}

Body:
{{ $json.text || $json.snippet }}

parameters.jsCode:
// Build the N8nEmailPayload that Finvora's backend expects

// Get the Gmail trigger data (from the first node)
const emailData = $('Gmail Trigger').first().json;

// Get OpenAI extraction result
const openaiResult = $input.first().json;

// Parse the tool call result
let extraction = {
  financial_type: 'UNKNOWN',
  confidence_score: 0.0
};

try {
  // n8n OpenAI node returns the tool call arguments as a parsed object
  if (openaiResult.message && openaiResult.message.tool_calls && openaiResult.message.tool_calls.length > 0) {
    const toolArgs = openaiResult.message.tool_calls[0].function.arguments;
    extraction = typeof toolArgs === 'string' ? JSON.parse(toolArgs) : toolArgs;
  } else if (openaiResult.text) {
    // Fallback: try parsing text response as JSON
    extraction = JSON.parse(openaiResult.text);
  }
} catch (e) {
  // Keep default unknown extraction
  console.log('Failed to parse OpenAI response:', e.message);
}

// Extract sender email
const senderRaw = emailData.from?.value?.[0]?.address || emailData.from || '';
const senderName = emailData.from?.value?.[0]?.name || '';
const sender = senderName ? `${senderName} <${senderRaw}>` : senderRaw;

// Build payload
const payload = {
  user_email: $env.FINVORA_USER_EMAIL, // Set this in n8n environment variables
  gmail_message_id: emailData.id,
  subject: emailData.subject || '(No Subject)',
  sender: sender,
  received_at: emailData.date || new Date().toISOString(),
  body: emailData.text || emailData.snippet || null,
  extraction: {
    financial_type: extraction.financial_type || 'UNKNOWN',
    vendor_name: extraction.vendor_name || null,
    vendor_email: extraction.vendor_email || null,
    amount: extraction.amount || null,
    currency: extraction.currency || 'INR',
    invoice_number: extraction.invoice_number || null,
    issue_date: extraction.issue_date || null,
    due_date: extraction.due_date || null,
    tax_amount: extraction.tax_amount || null,
    gst_number: extraction.gst_number || null,
    confidence_score: extraction.confidence_score || 0.0
  }
};

return [{ json: payload }];

// Log skipped non-financial email (optional — can delete this node)
const emailData = $input.first().json;
console.log(`Skipped non-financial email: "${emailData.subject}" from ${emailData.from?.value?.[0]?.address}`);
return [{ json: { status: 'skipped', subject: emailData.subject } }];
